SELECT AVG(latency) AS average_latency
FROM stream_metrics
WHERE stream_id = 1;

SELECT stream_id
FROM data_transfers
WHERE transfer_date = (
  SELECT MAX(transfer_date)
  FROM data_transfers
);

SELECT COUNT(DISTINCT event) 
FROM streams 
WHERE destination = 'localhost';

SELECT COUNT(DISTINCT stream_id)
FROM streams_status
WHERE status = 'Inactive' AND timestamp >= '2023-07-01 00:00:00';

SELECT 
  (SELECT COUNT(*) FROM streams) AS total_streams,
  (SELECT COUNT(*) FROM users) AS total_users;

SELECT COUNT(DISTINCT ns.stream_id) AS total_streams
FROM notification_settings ns
WHERE ns.notify_on_status_change = 1 AND ns.notify_via_email = 1;

SELECT stream_id
FROM stream_metrics
WHERE average_latency = (
  SELECT MAX(average_latency)
  FROM stream_metrics
);
